from agent import *from models.products import *import simplejsonimport reXCAT = ['Angebote', 'Neuheiten', 'Alle Kopfhörer']def remove_emoji(string):    emoji_pattern = re.compile("["                               u"\U0001F600-\U0001F64F"  # emoticons                               u"\U0001F300-\U0001F5FF"  # symbols & pictographs                               u"\U0001F680-\U0001F6FF"  # transport & map symbols                               u"\U0001F1E0-\U0001F1FF"  # flags (iOS)                               u"\U00002500-\U00002BEF"  # chinese char                               u"\U00002702-\U000027B0"                               u"\U00002702-\U000027B0"                               u"\U000024C2-\U0001F251"                               u"\U0001f926-\U0001f937"                               u"\U00010000-\U0010ffff"                               u"\u2640-\u2642"                               u"\u2600-\u2B55"                               u"\u200d"                               u"\u23cf"                               u"\u23e9"                               u"\u231a"                               u"\ufe0f"  # dingbats                               u"\u3030"                               "]+", flags=re.UNICODE)    return emoji_pattern.sub(r'', string)def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=10000)]    session.browser.use_new_parser = True    session.queue(Request('https://www.musik-produktiv.de/musikinstrumente.html'), process_catlist, dict())def process_catlist(data, context, session):    strip_namespace(data)    cats = data.xpath('//ul[@class="mp-navi-img"]/li/a')    if not cats:        process_prodlist(data, context, session)    for cat in cats:        name = cat.xpath('b/text()').string().strip()        url = cat.xpath('@href').string()        if name not in XCAT and 'für anfänger' not in name.lower():            session.queue(Request(url), process_catlist, dict(cat=context.get('cat', '')+'|'+name))def process_prodlist(data, context, session):    strip_namespace(data)    prods = data.xpath('//ul[contains(@class, "artgrid")]/li/a')    for prod in prods:        name = prod.xpath('@title').string()        url = prod.xpath('@href').string()        if '10076186' in url:            return        revs_cnt = prod.xpath('span/@data-review-count').string()        if revs_cnt and int(revs_cnt) > 0:            session.queue(Request(url), process_product, dict(context, name=name, url=url))    next_url = data.xpath('//li[@rel="next"]/@href').string()    if next_url:        session.queue(Request(next_url), process_prodlist, dict(context))def process_product(data, context, session):    strip_namespace(data)    product = Product()    product.name = context['name']    product.url = context['url']    product.category = context['cat'].replace(' und mehr', '').strip('| ')    product.manufacturer = data.xpath('//div/a[@class="markenlogo"]/@title ').string()    product.ssid = data.xpath('//div/@data-artnr').string()    product.sku = product.ssid    prod_data = data.xpath('''//script[contains(., '"@type":"Product"')]/text() ''').string()    if prod_data:        prod_data = simplejson.loads(prod_data)        ean = prod_data[0].get('gtin14')        if ean:            product.properties.append(ProductProperty(type='id.ean', value=str(ean)))    revs = data.xpath('//div[@class="review"] ')    for rev in revs:        review = Review()        review.type = 'user'        review.url = product.url        date = rev.xpath('i/text()').string()        if date:            review.date = date.split(' am ')[-1]        author = rev.xpath('i/text()').string()        if author:            author = remove_emoji(author.split(' am ')[0]).strip()            if author:                review.authors.append(Person(name=author, ssid=author))        grade_overall = rev.xpath('div/b//span/@style ').string()        if grade_overall:            grade_overall = float(grade_overall.split(': ')[-1].strip('%')) / 20            review.grades.append(Grade(name='Gesamteindruck', type="overall", value=grade_overall, best=5.0))        grades = rev.xpath("div/text()")        for grade in grades:            name = grade.string()            value = grade.xpath('following-sibling::span[1]/span/@style').string()            if name and value:                value = float(value.split(': ')[-1].strip('%')) / 20                review.grades.append(Grade(name=name, value=value, best=5.0))        excerpt = rev.xpath('p/text()').string(multiple=True)        title = rev.xpath('.//h3/text()').string()        if excerpt:            review.title = remove_emoji(title).strip() if title else ''        elif title:            excerpt = title        if excerpt:            excerpt = remove_emoji(excerpt).replace('<br/>', ' ').strip()            if excerpt:                review.properties.append(ReviewProperty(type="excerpt", value=excerpt))                review.ssid = review.digest(excerpt)                product.reviews.append(review)    if product.reviews:        session.emit(product)